import { d3_event } from '../../../core/d3-constants';
import { getMousePosition } from '../../../events/eventActions';

export function SizeNestedListener(d, index, ele, eventType) {
    let manager = this,
        event = d3_event(),
        node = event.srcElement || event.target,
        mouse = getMousePosition(node, event);

    let data = manager.getData(eventType, mouse, [d, index]);

    manager.associateBehaviours(eventType, data, mouse, event);
}
